import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { NavigationProvider } from './context/NavigationContext';
import Navbar from './components/Navbar';
import Notifications from './components/Notifications';
import Loading from './components/Loading';
import Home from './pages/Home';
import Login from './pages/Login';
import Register from './pages/Register';
import GameDetail from './pages/GameDetail';
import Cart from './pages/Cart';
import Profile from './pages/Profile';
import Favorites from './pages/Favorites';
import GoogleCallback from './pages/GoogleCallback';
import TestBackend from './pages/TestBackend';

const AdminDashboard = () => {
  const { state } = useAuth();
  const [games, setGames] = React.useState([
    {
      _id: '1',
      title: 'Fortnite - Account Level 150',
      description: 'حساب Fortnite بمستوى 150 مع شخصيات نادرة',
      price: 299.99,
      originalPrice: 399.99,
      discount: 25,
      category: 'battle-royale',
      platform: 'PC',
      image: 'https://via.placeholder.com/300x200/FF6B6B/FFFFFF?text=Fortnite',
      availability: 'available',
      region: 'Global',
      isNew: true
    },
    {
      _id: '2',
      title: 'PUBG Mobile - Account Level 100',
      description: 'حساب PUBG Mobile بمستوى 100 مع أسلحة نادرة',
      price: 199.99,
      category: 'battle-royale',
      platform: 'Mobile',
      image: 'https://via.placeholder.com/300x200/4ECDC4/FFFFFF?text=PUBG',
      availability: 'available',
      region: 'Global'
    },
    {
      _id: '3',
      title: 'Call of Duty - Premium Account',
      description: 'حساب COD مميز مع جميع الإضافات',
      price: 399.99,
      category: 'fps',
      platform: 'PC',
      image: 'https://via.placeholder.com/300x200/45B7D1/FFFFFF?text=COD',
      availability: 'available',
      region: 'Global'
    },
    {
      _id: '4',
      title: 'GTA V Online - Modded Account',
      description: 'حساب GTA V Online معدل مع ملايين',
      price: 149.99,
      originalPrice: 249.99,
      discount: 40,
      category: 'open-world',
      platform: 'PC',
      image: 'https://via.placeholder.com/300x200/96CEB4/FFFFFF?text=GTA',
      availability: 'available',
      region: 'Global',
      isNew: true
    }
  ]);
  const [loading, setLoading] = React.useState(false);
  const [activeTab, setActiveTab] = React.useState('games');
  const [searchQuery, setSearchQuery] = React.useState('');
  const [platformFilter, setPlatformFilter] = React.useState('all');
  const [showAddForm, setShowAddForm] = React.useState(false);
  const [gameForm, setGameForm] = React.useState({
    title: '',
    description: '',
    price: '',
    platform: 'PC',
    availability: 'available'
  });

  React.useEffect(() => {
    if (state.isAuthenticated && state.user?.role === 'admin') {
      fetchGames();
    }
  }, [state.isAuthenticated]);

  const fetchGames = async () => {
    setLoading(true);
    setTimeout(() => {
      setLoading(false);
    }, 1000);
  };

  const handleAddGame = (e: any) => {
    e.preventDefault();
    alert('تمت إضافة اللعبة بنجاح!');
    setShowAddForm(false);
    setGameForm({
      title: '',
      description: '',
      price: '',
      platform: 'PC',
      availability: 'available'
    });
  };

  const handleEditPrice = (gameId: any) => {
    const newPrice = prompt('أدخل السعر الجديد:');
    if (newPrice) {
      alert('تم تحديث السعر بنجاح!');
    }
  };

  const handleAddDiscount = (gameId: any) => {
    const discount = prompt('أدخل نسبة الخصم:');
    if (discount) {
      alert(`تم إضافة خصم ${discount}% بنجاح!`);
    }
  };

  const handleDeleteGame = (gameId: any) => {
    if (window.confirm('هل أنت متأكد من حذف هذه اللعبة؟')) {
      alert('تم حذف اللعبة بنجاح!');
    }
  };

  if (!state.isAuthenticated || state.user?.role !== 'admin') {
    return (
      <div className="min-h-screen bg-gray-900 text-white flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-4xl font-bold mb-4">غير مصرح بالوصول</h1>
          <p className="text-xl mb-8">يجب تسجيل الدخول كمدير للوصول إلى هذه الصفحة</p>
          <Navigate to="/login" replace />
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-900 text-white p-6">
      <div className="max-w-7xl mx-auto">
        <div className="mb-8">
          <h1 className="text-4xl font-bold mb-2">لوحة تحكم الإدمن</h1>
          <p className="text-gray-400">مرحباً Admin</p>
        </div>

        <div className="mb-6">
          <nav className="flex space-x-4">
            <button
              onClick={() => setActiveTab('games')}
              className={`px-4 py-2 rounded-lg font-medium transition-colors ${
                activeTab === 'games'
                  ? 'bg-red-600 text-white'
                  : 'bg-gray-700 text-gray-300 hover:bg-gray-600'
              }`}
            >
              إدارة الألعاب
            </button>
            <button
              onClick={() => setActiveTab('users')}
              className={`px-4 py-2 rounded-lg font-medium transition-colors ${
                activeTab === 'users'
                  ? 'bg-red-600 text-white'
                  : 'bg-gray-700 text-gray-300 hover:bg-gray-600'
              }`}
            >
              إدارة المستخدمين
            </button>
            <button
              onClick={() => setActiveTab('orders')}
              className={`px-4 py-2 rounded-lg font-medium transition-colors ${
                activeTab === 'orders'
                  ? 'bg-red-600 text-white'
                  : 'bg-gray-700 text-gray-300 hover:bg-gray-600'
              }`}
            >
              إدارة الطلبات
            </button>
          </nav>
        </div>

        {activeTab === 'games' && (
          <div>
            <div className="mb-6 flex flex-col sm:flex-row gap-4 items-center justify-between">
              <div className="flex flex-col sm:flex-row gap-4 w-full sm:w-auto">
                <div className="relative">
                  <input
                    type="text"
                    placeholder="البحث عن لعبة..."
                    value={searchQuery}
                    onChange={(e: any) => setSearchQuery(e.target.value)}
                    className="pl-10 pr-4 py-2 bg-gray-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500 w-full sm:w-64"
                  />
                  <svg
                    className="absolute right-3 top-2.5 w-5 h-5 text-gray-400"
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"
                    />
                  </svg>
                </div>
                <select
                  value={platformFilter}
                  onChange={(e: any) => setPlatformFilter(e.target.value)}
                  className="px-4 py-2 bg-gray-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
                >
                  <option value="all">جميع المنصات</option>
                  <option value="PC">PC</option>
                  <option value="Mobile">Mobile</option>
                  <option value="Console">Console</option>
                </select>
              </div>
              <button
                onClick={() => setShowAddForm(!showAddForm)}
                className="bg-red-600 hover:bg-red-700 text-white px-4 py-2 rounded-lg font-medium transition-colors w-full sm:w-auto"
              >
                {showAddForm ? 'إلغاء' : '+ إضافة لعبة جديدة'}
              </button>
            </div>

            {showAddForm && (
              <div className="mb-6 bg-gray-800 p-6 rounded-lg">
                <h2 className="text-xl font-bold mb-4">إضافة لعبة جديدة</h2>
                <form onSubmit={handleAddGame} className="space-y-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium mb-2">اسم اللعبة</label>
                      <input
                        type="text"
                        value={gameForm.title}
                        onChange={(e: any) => setGameForm({...gameForm, title: e.target.value})}
                        className="w-full px-3 py-2 bg-gray-700 text-white rounded-md focus:outline-none focus:ring-2 focus:ring-red-500"
                        required
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium mb-2">السعر</label>
                      <input
                        type="number"
                        value={gameForm.price}
                        onChange={(e: any) => setGameForm({...gameForm, price: e.target.value})}
                        className="w-full px-3 py-2 bg-gray-700 text-white rounded-md focus:outline-none focus:ring-2 focus:ring-red-500"
                        required
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-2">الوصف</label>
                    <textarea
                      value={gameForm.description}
                      onChange={(e: any) => setGameForm({...gameForm, description: e.target.value})}
                      className="w-full px-3 py-2 bg-gray-700 text-white rounded-md focus:outline-none focus:ring-2 focus:ring-red-500"
                      rows={4}
                      required
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-2">المنصة</label>
                    <select
                      value={gameForm.platform}
                      onChange={(e: any) => setGameForm({...gameForm, platform: e.target.value})}
                      className="w-full px-3 py-2 bg-gray-700 text-white rounded-md focus:outline-none focus:ring-2 focus:ring-red-500"
                    >
                      <option value="PC">PC</option>
                      <option value="Mobile">Mobile</option>
                      <option value="Console">Console</option>
                    </select>
                  </div>
                  <div className="flex gap-4">
                    <button
                      type="submit"
                      className="bg-red-600 hover:bg-red-700 text-white px-6 py-2 rounded-md font-medium transition-colors"
                    >
                      حفظ اللعبة
                    </button>
                    <button
                      type="button"
                      onClick={() => setShowAddForm(false)}
                      className="bg-gray-600 hover:bg-gray-700 text-white px-6 py-2 rounded-md font-medium transition-colors"
                    >
                      إلغاء
                    </button>
                  </div>
                </form>
              </div>
            )}

            <div className="bg-gray-800 rounded-lg overflow-hidden">
              <div className="p-4 border-b border-gray-700">
                <h2 className="text-xl font-bold">قائمة الألعاب</h2>
                <p className="text-gray-400">إدارة الألعاب المتوفرة في المتجر</p>
              </div>

              {loading ? (
                <div className="p-8 text-center">
                  <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-red-600"></div>
                  <p className="mt-2">جاري التحميل...</p>
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <table className="w-full">
                    <thead className="bg-gray-700">
                      <tr>
                        <th className="px-6 py-3 text-right text-xs font-medium text-gray-300 uppercase tracking-wider">صورة</th>
                        <th className="px-6 py-3 text-right text-xs font-medium text-gray-300 uppercase tracking-wider">اسم اللعبة</th>
                        <th className="px-6 py-3 text-right text-xs font-medium text-gray-300 uppercase tracking-wider">السعر</th>
                        <th className="px-6 py-3 text-right text-xs font-medium text-gray-300 uppercase tracking-wider">المنصة</th>
                        <th className="px-6 py-3 text-right text-xs font-medium text-gray-300 uppercase tracking-wider">الحالة</th>
                        <th className="px-6 py-3 text-right text-xs font-medium text-gray-300 uppercase tracking-wider">الإجراءات</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-700">
                      {games.map((game: any) => (
                        <tr key={game._id} className="hover:bg-gray-700 transition-colors">
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="flex-shrink-0 h-16 w-16">
                              <img
                                className="h-16 w-16 rounded-lg object-cover"
                                src={game.image}
                                alt={game.title}
                              />
                            </div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="text-sm font-medium text-white">{game.title}</div>
                            <div className="text-sm text-gray-400">{game.category}</div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="text-sm text-white">
                              ${game.price}
                              {game.discount && game.originalPrice && (
                                <div className="text-xs text-gray-400 line-through">
                                  ${game.originalPrice}
                                </div>
                              )}
                            </div>
                            {game.discount && (
                              <div className="text-xs text-green-400">
                                -{game.discount}%
                              </div>
                            )}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="flex items-center">
                              {game.platform === 'PC' && (
                                <svg className="h-5 w-5 text-blue-400" fill="currentColor" viewBox="0 0 20 20">
                                  <path d="M3 4a1 1 0 011-1h12a1 1 0 011 1v2a1 1 0 01-1 1H4a1 1 0 01-1-1V4zM3 10a1 1 0 011-1h6a1 1 0 011 1v6a1 1 0 01-1 1H4a1 1 0 01-1-1v-6zM14 9a1 1 0 00-1 1v6a1 1 0 001 1h2a1 1 0 001-1v-6a1 1 0 00-1-1h-2z" />
                                </svg>
                              )}
                              {game.platform === 'Mobile' && (
                                <svg className="h-5 w-5 text-green-400" fill="currentColor" viewBox="0 0 20 20">
                                  <path d="M7 2a2 2 0 00-2 2v12a2 2 0 002 2h6a2 2 0 002-2V4a2 2 0 00-2-2H7zm3 14a1 1 0 100-2 1 1 0 000 2z" />
                                </svg>
                              )}
                              <span className="mr-2 text-sm text-gray-300">{game.platform}</span>
                            </div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${
                              game.availability === 'available' 
                                ? 'bg-green-100 text-green-800' 
                                : 'bg-red-100 text-red-800'
                            }`}>
                              {game.availability === 'available' ? 'متاحة' : 'غير متاحة'}
                            </span>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                            <div className="flex space-x-2 space-x-reverse">
                              <button
                                onClick={() => handleEditPrice(game._id)}
                                className="text-blue-400 hover:text-blue-300 transition-colors duration-200 transform hover:scale-110"
                                title="تعديل السعر"
                              >
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                                </svg>
                              </button>
                              <button
                                onClick={() => handleAddDiscount(game._id)}
                                className="text-green-400 hover:text-green-300 transition-colors duration-200 transform hover:scale-110"
                                title="إضافة خصم"
                              >
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                                </svg>
                              </button>
                              <button
                                onClick={() => handleDeleteGame(game._id)}
                                className="text-red-400 hover:text-red-300 transition-colors duration-200 transform hover:scale-110"
                                title="حذف اللعبة"
                              >
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                </svg>
                              </button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        )}

        {activeTab === 'users' && (
          <div className="bg-gray-800 rounded-lg p-6">
            <h2 className="text-xl font-bold mb-4">إدارة المستخدمين</h2>
            <p className="text-gray-400">سيتم تنفيذ هذه الميزة قريباً</p>
          </div>
        )}

        {activeTab === 'orders' && (
          <div className="bg-gray-800 rounded-lg p-6">
            <h2 className="text-xl font-bold mb-4">إدارة الطلبات</h2>
            <p className="text-gray-400">سيتم تنفيذ هذه الميزة قريباً</p>
          </div>
        )}
      </div>
    </div>
  );
};

const App = () => {
  return (
    <Router>
      <AuthProvider>
        <NavigationProvider>
          <div className="min-h-screen bg-gray-900 text-white">
            <Navbar />
            <main className="container mx-auto px-4 py-8">
              <Routes>
                <Route path="/" element={<Home />} />
                <Route path="/login" element={<Login />} />
                <Route path="/register" element={<Register />} />
                <Route path="/game/:id" element={<GameDetail />} />
                <Route path="/cart" element={<Cart />} />
                <Route path="/profile" element={<Profile />} />
                <Route path="/favorites" element={<Favorites />} />
                <Route path="/google/callback" element={<GoogleCallback />} />
                <Route path="/test-backend" element={<TestBackend />} />
                <Route path="/admin" element={<AdminDashboard />} />
                <Route path="*" element={<Navigate to="/" replace />} />
              </Routes>
            </main>
            <Notifications />
          </div>
        </NavigationProvider>
      </AuthProvider>
    </Router>
  );
};

export default App;
